generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "sqlite"
  url      = env("DATABASE_URL")
}

enum IssueStatus {
  OPEN
  IN_PROGRESS
  DONE
}

enum IssuePriority {
  LOW
  MEDIUM
  HIGH
}

model Issue {
  id          String          @id @default(cuid())
  title       String
  description String?
  status      IssueStatus     @default(OPEN)
  priority    IssuePriority   @default(MEDIUM)
  dueDate     DateTime?
  createdAt   DateTime        @default(now())
  updatedAt   DateTime        @updatedAt
  comments    Comment[]
  issueLabels IssueLabel[]
}

model Comment {
  id        String   @id @default(cuid())
  issueId   String
  body      String
  createdAt DateTime @default(now())
  issue      Issue   @relation(fields: [issueId], references: [id], onDelete: Cascade)
}

model Label {
  id          String       @id @default(cuid())
  name        String       @unique
  issueLabels IssueLabel[]
}

model IssueLabel {
  issueId String
  labelId String
  issue   Issue @relation(fields: [issueId], references: [id], onDelete: Cascade)
  label   Label @relation(fields: [labelId], references: [id], onDelete: Cascade)

  @@id([issueId, labelId])
}

export function formatDate(value: Date | string | null | undefined) {
  if (!value) {
    return "-";
  }

  return new Intl.DateTimeFormat("ja-JP", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).format(new Date(value));
}

export function toDateOrNull(value: string | undefined) {
  if (!value) {
    return null;
  }

  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

import type { IssuePriority, IssueStatus } from "@prisma/client";

export type IssueListQuery = {
  q?: string;
  status?: IssueStatus | "ALL";
  priority?: IssuePriority | "ALL";
  sort?: "updatedAt" | "createdAt" | "dueDate" | "priority";
};

export type IssueFormInput = {
  title: string;
  description?: string;
  status?: IssueStatus;
  priority: IssuePriority;
  dueDate?: string;
  labelIds: string[];
};

export type CommentInput = {
  body: string;
};

import { IssuePriority, IssueStatus } from "@prisma/client";
import { z } from "zod";

const optionalDate = z
  .string()
  .trim()
  .optional()
  .refine((value) => !value || !Number.isNaN(Date.parse(value)), {
    message: "dueDate must be a valid date",
  });

export const issueInputSchema = z.object({
  title: z.string().trim().min(1, "title is required"),
  description: z.string().trim().optional().or(z.literal("")),
  status: z.nativeEnum(IssueStatus).optional(),
  priority: z.nativeEnum(IssuePriority),
  dueDate: optionalDate,
  labelIds: z.array(z.string()).default([]),
});

export const commentInputSchema = z.object({
  body: z.string().trim().min(1, "body is required"),
});

export const issueQuerySchema = z.object({
  q: z.string().trim().optional(),
  status: z.nativeEnum(IssueStatus).optional(),
  priority: z.nativeEnum(IssuePriority).optional(),
  sort: z.enum(["updatedAt", "createdAt", "dueDate", "priority"]).optional(),
});

import { PrismaClient } from "@prisma/client";

const globalForPrisma = globalThis as unknown as {
  prisma?: PrismaClient;
};

export const prisma =
  globalForPrisma.prisma ??
  new PrismaClient({
    log: process.env.NODE_ENV === "development" ? ["error", "warn"] : ["error"],
  });

if (process.env.NODE_ENV !== "production") {
  globalForPrisma.prisma = prisma;
}

import { IssuePriority, IssueStatus } from "@prisma/client";

export const issueStatuses = Object.values(IssueStatus);
export const issuePriorities = Object.values(IssuePriority);

import { PrismaClient, IssuePriority, IssueStatus } from "@prisma/client";

const prisma = new PrismaClient();

async function main() {
  await prisma.comment.deleteMany();
  await prisma.issueLabel.deleteMany();
  await prisma.label.deleteMany();
  await prisma.issue.deleteMany();

  const labels = await Promise.all(
    ["bug", "backend", "frontend", "urgent"].map((name) =>
      prisma.label.create({ data: { name } }),
    ),
  );

  const [bug, backend, frontend, urgent] = labels;

  const issueA = await prisma.issue.create({
    data: {
      title: "Seeded open issue",
      description: "Investigate list performance.",
      status: IssueStatus.OPEN,
      priority: IssuePriority.MEDIUM,
      dueDate: new Date("2026-04-15"),
      issueLabels: {
        create: [{ labelId: backend.id }],
      },
    },
  });

  const issueB = await prisma.issue.create({
    data: {
      title: "Seeded in-progress issue",
      description: "Improve issue detail layout.",
      status: IssueStatus.IN_PROGRESS,
      priority: IssuePriority.HIGH,
      dueDate: new Date("2026-04-12"),
      issueLabels: {
        create: [{ labelId: frontend.id }, { labelId: urgent.id }],
      },
    },
  });

  const issueC = await prisma.issue.create({
    data: {
      title: "Seeded done issue",
      description: "API validation baseline completed.",
      status: IssueStatus.DONE,
      priority: IssuePriority.LOW,
      issueLabels: {
        create: [{ labelId: bug.id }],
      },
    },
  });

  await prisma.comment.createMany({
    data: [
      { issueId: issueA.id, body: "Need benchmark data before changing query." },
      { issueId: issueB.id, body: "UI draft is ready for review." },
      { issueId: issueC.id, body: "Regression checks passed." },
    ],
  });
}

main()
  .catch((error) => {
    console.error(error);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

