+import { IssuePriority, IssueStatus, Prisma } from "@prisma/client";
+
+import { prisma } from "@/lib/prisma";
+import { toDateOrNull } from "@/lib/utils";
+import type { CommentInput, IssueFormInput, IssueListQuery } from "@/lib/types";
+
+export async function listLabels() {
+  return prisma.label.findMany({ orderBy: { name: "asc" } });
+}
+
+export async function listIssues(query: IssueListQuery = {}) {
+  const where: Prisma.IssueWhereInput = {
+    ...(query.q
+      ? {
+          OR: [
+            { title: { contains: query.q } },
+            { description: { contains: query.q } },
+            { issueLabels: { some: { label: { name: { contains: query.q } } } } },
+          ],
+        }
+      : {}),
+    ...(query.status && query.status !== "ALL" ? { status: query.status } : {}),
+    ...(query.priority && query.priority !== "ALL"
+      ? { priority: query.priority }
+      : {}),
+  };
+
+  const orderBy: Prisma.IssueOrderByWithRelationInput =
+    query.sort === "createdAt"
+      ? { createdAt: "desc" }
+      : query.sort === "dueDate"
+        ? { dueDate: "asc" }
+        : query.sort === "priority"
+          ? { priority: "desc" }
+          : { updatedAt: "desc" };
+
+  return prisma.issue.findMany({
+    where,
+    orderBy,
+    include: {
+      comments: { orderBy: { createdAt: "desc" } },
+      issueLabels: {
+        include: {
+          label: true,
+        },
+      },
+    },
+  });
+}
+
+export async function getIssueById(id: string) {
+  return prisma.issue.findUnique({
+    where: { id },
+    include: {
+      comments: { orderBy: { createdAt: "desc" } },
+      issueLabels: {
+        include: {
+          label: true,
+        },
+      },
+    },
+  });
+}
+
+export async function createIssue(input: IssueFormInput) {
+  return prisma.issue.create({
+    data: {
+      title: input.title.trim(),
+      description: input.description?.trim() || null,
+      status: IssueStatus.OPEN,
+      priority: input.priority,
+      dueDate: toDateOrNull(input.dueDate),
+      issueLabels: {
+        create: input.labelIds.map((labelId) => ({ labelId })),
+      },
+    },
+    include: {
+      comments: true,
+      issueLabels: { include: { label: true } },
+    },
+  });
+}
+
+export async function updateIssue(id: string, input: IssueFormInput) {
+  return prisma.issue.update({
+    where: { id },
+    data: {
+      title: input.title.trim(),
+      description: input.description?.trim() || null,
+      status: input.status ?? IssueStatus.OPEN,
+      priority: input.priority,
+      dueDate: toDateOrNull(input.dueDate),
+      issueLabels: {
+        deleteMany: {},
+        create: input.labelIds.map((labelId) => ({ labelId })),
+      },
+    },
+    include: {
+      comments: true,
+      issueLabels: { include: { label: true } },
+    },
+  });
+}
+
+export async function deleteIssue(id: string) {
+  await prisma.issue.delete({ where: { id } });
+}
+
+export async function addComment(issueId: string, input: CommentInput) {
+  return prisma.comment.create({
+    data: {
+      issueId,
+      body: input.body.trim(),
+    },
+  });
+}
+
+export async function setIssueStatus(id: string, status: IssueStatus) {
+  return prisma.issue.update({
+    where: { id },
+    data: { status },
+  });
+}
+
+export function serializeIssue(issue: Awaited<ReturnType<typeof getIssueById>>) {
+  if (!issue) {
+    return null;
+  }
+
+  return {
+    ...issue,
+    createdAt: issue.createdAt.toISOString(),
+    updatedAt: issue.updatedAt.toISOString(),
+    dueDate: issue.dueDate?.toISOString() ?? null,
+    comments: issue.comments.map((comment) => ({
+      ...comment,
+      createdAt: comment.createdAt.toISOString(),
+    })),
+  };
+}
+
+export function serializeIssues(issues: Awaited<ReturnType<typeof listIssues>>) {
+  return issues.map((issue) => ({
+    ...issue,
+    createdAt: issue.createdAt.toISOString(),
+    updatedAt: issue.updatedAt.toISOString(),
+    dueDate: issue.dueDate?.toISOString() ?? null,
+    comments: issue.comments.map((comment) => ({
+      ...comment,
+      createdAt: comment.createdAt.toISOString(),
+    })),
+  }));
+}
