import { SearchToolbar } from "@/components/search-toolbar";
import { IssueList } from "@/components/issue-list";
import { issueQuerySchema } from "@/lib/validators";
import { listIssues, serializeIssues } from "@/server/issues";

type IssuesPageProps = {
  searchParams: Promise<Record<string, string | string[] | undefined>>;
};

export default async function IssuesPage({ searchParams }: IssuesPageProps) {
  const raw = await searchParams;
  const parsed = issueQuerySchema.safeParse({
    q: typeof raw.q === "string" ? raw.q : undefined,
    status: typeof raw.status === "string" ? raw.status : undefined,
    priority: typeof raw.priority === "string" ? raw.priority : undefined,
    sort: typeof raw.sort === "string" ? raw.sort : undefined,
  });

  const query = parsed.success ? parsed.data : {};
  const issues = serializeIssues(await listIssues(query));

  return (
    <main className="page-shell">
      <div className="container">
        <section className="hero">
          <div className="hero-card">
            <p className="muted">Issue Tracker Lite</p>
            <h1 className="hero-title">Benchmark fixture for full-stack issue work.</h1>
            <p className="hero-subtitle">
              Frontend, API, DB, test, and Docker changes can be evaluated in one
              fixed application.
            </p>
          </div>
        </section>
        <section className="stack">
          <SearchToolbar
            q={query.q}
            status={query.status}
            priority={query.priority}
            sort={query.sort}
          />
          <IssueList issues={issues} />
        </section>
      </div>
    </main>
  );
}

import type { Metadata } from "next";
import "./globals.css";

