"use server";

import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";

import { commentInputSchema, issueInputSchema } from "@/lib/validators";
import {
  addComment,
  createIssue,
  deleteIssue,
  setIssueStatus,
  updateIssue,
} from "@/server/issues";

function getString(formData: FormData, key: string) {
  return String(formData.get(key) ?? "");
}

export async function createIssueAction(formData: FormData) {
  const parsed = issueInputSchema.parse({
    title: getString(formData, "title"),
    description: getString(formData, "description"),
    priority: getString(formData, "priority"),
    dueDate: getString(formData, "dueDate"),
    labelIds: formData.getAll("labelIds").map(String),
  });

  const issue = await createIssue(parsed);
  revalidatePath("/issues");
  redirect(`/issues/${issue.id}`);
}

export async function updateIssueAction(issueId: string, formData: FormData) {
  const parsed = issueInputSchema.extend({ status: issueInputSchema.shape.priority }).parse({
    title: getString(formData, "title"),
    description: getString(formData, "description"),
    status: getString(formData, "status"),
    priority: getString(formData, "priority"),
    dueDate: getString(formData, "dueDate"),
    labelIds: formData.getAll("labelIds").map(String),
  });

  await updateIssue(issueId, parsed);
  revalidatePath("/issues");
  revalidatePath(`/issues/${issueId}`);
  redirect(`/issues/${issueId}`);
}

export async function deleteIssueAction(issueId: string) {
  await deleteIssue(issueId);
  revalidatePath("/issues");
  redirect("/issues");
}

export async function addCommentAction(issueId: string, formData: FormData) {
  const parsed = commentInputSchema.parse({
    body: getString(formData, "body"),
  });

  await addComment(issueId, parsed);
  revalidatePath(`/issues/${issueId}`);
}

export async function updateStatusAction(issueId: string, formData: FormData) {
  const status = getString(formData, "status");
  await setIssueStatus(issueId, status as never);
  revalidatePath("/issues");
  revalidatePath(`/issues/${issueId}`);
}

