import { beforeEach, describe, expect, test, vi } from "vitest";

const issue = {
  id: "issue-1",
  title: "Alpha",
  description: "Desc",
  status: "OPEN",
  priority: "HIGH",
  dueDate: null,
  createdAt: new Date("2026-04-08T00:00:00.000Z"),
  updatedAt: new Date("2026-04-08T00:00:00.000Z"),
  comments: [],
  issueLabels: [],
};

const issueModule = vi.hoisted(() => ({
  listIssues: vi.fn(),
  createIssue: vi.fn(),
  getIssueById: vi.fn(),
  updateIssue: vi.fn(),
  deleteIssue: vi.fn(),
  addComment: vi.fn(),
  serializeIssues: vi.fn((issues: typeof issue[]) => issues),
  serializeIssue: vi.fn((value: typeof issue | null) => value),
}));

vi.mock("@/server/issues", () => issueModule);

describe("issues api routes", () => {
  beforeEach(() => {
    vi.resetAllMocks();
  });

  test("GET /api/issues returns list", async () => {
    const { GET } = await import("@/app/api/issues/route");
    issueModule.listIssues.mockResolvedValue([issue]);

    const response = await GET(
      new Request("http://localhost:3000/api/issues?q=Alpha"),
    );

    expect(response.status).toBe(200);
    expect(issueModule.listIssues).toHaveBeenCalled();
  });

  test("POST /api/issues validates payload", async () => {
    const { POST } = await import("@/app/api/issues/route");

    const response = await POST(
      new Request("http://localhost:3000/api/issues", {
        method: "POST",
        body: JSON.stringify({ title: "", priority: "LOW", labelIds: [] }),
      }),
    );

    expect(response.status).toBe(400);
  });

  test("GET /api/issues/:id returns 404 for missing issue", async () => {
    const { GET } = await import("@/app/api/issues/[id]/route");
    issueModule.getIssueById.mockResolvedValue(null);

    const response = await GET(new Request("http://localhost"), {
      params: Promise.resolve({ id: "missing" }),
    });

    expect(response.status).toBe(404);
  });
});

